// =================================================================
// PM WELCOME MODAL — shown on first sign-in and from the "How this works" button
// =================================================================
// =================================================================
// TRANSLATE BUTTON — small UI for translating an assignment's text
// Uses the Google Translate API key configured at the top of this file.
// Hidden entirely if no key is configured.
// =================================================================
// =================================================================
// SPANISH TRANSLATION PANEL — collapsible "ES — Spanish version available"
// pill that expands to show the pre-computed Spanish translation of an
// assignment's attachment. Only renders when there's actually a translation.
// =================================================================
function SpanishTranslationPanel({ assignment, viewerRole }) {
  const [expanded, setExpanded] = useState(false);
  const [retrying, setRetrying] = useState(false);
  if (!assignment) return null;
  // Master kill switch: if translation feature is off, render nothing
  // regardless of whether existing assignments have stored Spanish text.
  if (!TRANSLATION_ENABLED) return null;

  const status = assignment.translation_status;
  const spanish = assignment.spanish_translation;
  const hasSpanish = !!(spanish && spanish.trim());
  // Only owners and managers see translation pipeline errors / skipped notes.
  // PMs and cleaners just see "in progress" or the final ES pill.
  const isStaff = viewerRole === 'owner' || viewerRole === 'manager';

  const retry = async () => {
    if (!assignment.file_url) return;
    setRetrying(true);
    try {
      await supabase.from('assignments').update({
        translation_status: 'pending',
        translation_error: null,
      }).eq('id', assignment.id);
      // Kick off auto-translate; fire-and-forget
      autoTranslateAssignment(assignment.id, assignment.file_url, assignment.file_kind);
    } finally {
      setRetrying(false);
    }
  };

  // Show different states based on translation status
  if (status === 'processing' || status === 'pending') {
    // Only show the "in progress" spinner to owners/managers — PMs and cleaners
    // don't know about the auto-translation pipeline, no point exposing it.
    if (!isStaff) return null;
    return (
      <div className="mt-2 px-3 py-1.5 rounded-full bg-stone-100 inline-flex items-center gap-1.5 text-xs font-mono text-stone-500">
        <div className="w-2 h-2 rounded-full border border-stone-400 border-t-transparent animate-spin" />
        Spanish translation in progress…
      </div>
    );
  }
  if (status === 'skipped') {
    // Nothing readable in attachment — quietly hide for cleaners, show small note to staff
    if (!isStaff) return null;
    return (
      <div className="mt-2 px-3 py-1.5 rounded-full bg-stone-100 inline-flex items-center gap-1.5 text-xs font-mono text-stone-500">
        No readable text in attachment — translation skipped.
      </div>
    );
  }
  if (status === 'failed' && !hasSpanish) {
    // Failed — only show to staff so they can fix it; hide from cleaners
    if (!isStaff) return null;
    return (
      <div className="mt-2 p-3 rounded-xl bg-red-50 border border-red-200">
        <div className="flex items-start justify-between gap-2">
          <div className="flex-1">
            <div className="text-[10px] uppercase tracking-wider font-mono text-red-700 mb-1 flex items-center gap-1.5">
              <AlertCircle size={11} /> Auto-translation failed
            </div>
            {assignment.translation_error && (
              <div className="text-xs text-red-800 font-mono break-words">
                {assignment.translation_error}
              </div>
            )}
            <div className="text-[10px] text-red-700 mt-1">
              Cleaners can't see this — only you. Common fixes: enable Cloud Vision API in Google Cloud Console, or add it to your API key's allowed API list.
            </div>
          </div>
          <button onClick={retry} disabled={retrying}
            className="px-3 py-1 rounded-full bg-red-700 text-white text-[11px] font-mono active:scale-95 disabled:opacity-50 flex-shrink-0">
            {retrying ? 'Retrying…' : 'Retry'}
          </button>
        </div>
      </div>
    );
  }
  if (!hasSpanish) {
    return null;
  }

  return (
    <div className="mt-2">
      <button onClick={() => setExpanded(e => !e)}
        className={`inline-flex items-center gap-1.5 px-3 py-1.5 rounded-full text-xs font-mono active:scale-95 transition-all ${expanded ? 'bg-amber-200 text-amber-900' : 'bg-amber-100 hover:bg-amber-200 text-amber-900'}`}>
        <span className="font-bold tracking-wider">ES</span>
        <span>{expanded ? 'Hide Spanish version' : 'Spanish version available'}</span>
        <ChevronRight size={11} className={`transition-transform ${expanded ? 'rotate-90' : ''}`} />
      </button>
      {expanded && (
        <div className="mt-2 p-3 rounded-xl bg-amber-50 border border-amber-200">
          <div className="flex items-center gap-1.5 text-[10px] uppercase tracking-wider font-mono text-amber-800 mb-2">
            <Languages size={11} /> Traducción al español
          </div>
          <div className="text-sm text-stone-800 whitespace-pre-wrap break-words">
            {spanish}
          </div>
        </div>
      )}
    </div>
  );
}

function TranslateButton({ texts, defaultTargetLang = 'es' }) {
  const [open, setOpen] = useState(false);
  const [targetLang, setTargetLang] = useState(() => {
    try { return localStorage.getItem('tt_translate_target') || defaultTargetLang; } catch { return defaultTargetLang; }
  });
  const [translated, setTranslated] = useState(null); // array of { translatedText, detectedSourceLanguage }
  const [busy, setBusy] = useState(false);
  const [error, setError] = useState('');

  if (!isTranslateConfigured()) return null;
  const inputs = (Array.isArray(texts) ? texts : [texts]).filter(Boolean);
  if (inputs.length === 0) return null;

  const doTranslate = async (lang) => {
    setBusy(true); setError('');
    try {
      const out = await translateText(inputs, lang);
      setTranslated(out);
      try { localStorage.setItem('tt_translate_target', lang); } catch {}
    } catch (e) {
      setError(e.message || String(e));
    } finally {
      setBusy(false);
    }
  };

  const langLabel = SUPPORTED_TRANSLATE_LANGUAGES.find(l => l.code === targetLang)?.label || targetLang;

  return (
    <div className="mt-2">
      {!translated ? (
        <div className="flex items-center gap-2 flex-wrap">
          <button onClick={() => setOpen(o => !o)}
            disabled={busy}
            className="flex items-center gap-1.5 px-3 py-1.5 rounded-full bg-amber-100 hover:bg-amber-200 text-amber-900 text-xs font-mono active:scale-95 transition-all disabled:opacity-50">
            <Languages size={12} />
            {busy ? 'Translating…' : 'Translate'}
            <ChevronRight size={10} className={`transition-transform ${open ? 'rotate-90' : ''}`} />
          </button>
          {open && (
            <select autoFocus value="" onChange={(e) => { if (e.target.value) { setTargetLang(e.target.value); doTranslate(e.target.value); } }}
              disabled={busy}
              className="text-xs font-mono px-2 py-1.5 rounded-lg border border-stone-300 bg-white">
              <option value="" disabled>Choose language…</option>
              {SUPPORTED_TRANSLATE_LANGUAGES.map(l => (
                <option key={l.code} value={l.code}>{l.label}</option>
              ))}
            </select>
          )}
        </div>
      ) : (
        <div className="mt-1 p-3 rounded-xl bg-amber-50 border border-amber-200">
          <div className="flex items-center justify-between mb-2">
            <div className="flex items-center gap-1.5 text-[10px] uppercase tracking-wider font-mono text-amber-800">
              <Languages size={11} /> Translated to {langLabel}
            </div>
            <div className="flex items-center gap-2">
              <select value={targetLang} onChange={(e) => { setTargetLang(e.target.value); doTranslate(e.target.value); }}
                disabled={busy}
                className="text-[10px] font-mono px-2 py-0.5 rounded border border-amber-300 bg-white">
                {SUPPORTED_TRANSLATE_LANGUAGES.map(l => (
                  <option key={l.code} value={l.code}>{l.label}</option>
                ))}
              </select>
              <button onClick={() => setTranslated(null)}
                className="text-[10px] font-mono text-stone-500 hover:text-stone-800">
                Hide
              </button>
            </div>
          </div>
          {busy ? (
            <div className="text-xs text-amber-700 italic">Translating…</div>
          ) : (
            <div className="space-y-2">
              {translated.map((t, i) => (
                <div key={i} className="text-sm text-stone-800 whitespace-pre-wrap">
                  {t.translatedText}
                </div>
              ))}
            </div>
          )}
        </div>
      )}
      {error && (
        <div className="mt-1 text-xs text-red-600 flex items-center gap-1">
          <AlertCircle size={12} /> {error}
        </div>
      )}
    </div>
  );
}


